def minMutation(start, end, bank):
    q = collections.deque([(start, 0)]); b = set(bank)
    while q:
        s, d = q.popleft()
        if s == end: return d
        for i in range(len(s)):
            for c in 'ACGT':
                t = s[:i] + c + s[i+1:]
                if t in b:
                    q.append((t, d+1)); b.remove(t)
    return -1

